INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (100211, 20022, 0, "どういたしまして♪\nケガはないのが一番だけど、\n困ったときは遠慮なく相談してね？", 11, 0, 0, 1, 1, 10, 1200220013);
