INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (105611, 20052, 0, "そうかい。\nじゃあまずは、焚火の枝を集める運命を\n受け入れてもらえるかい？", 11, 0, 0, 1, 1, 10, 1200520010);
