INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (103211, 20152, 0.2, "travel_topdrama_r_2000_talk_doya_in_surprise", 3, "", "", "travel_topdrama_r_2000_talk_doya_loop_surprise", 1, 0, 1201520013);
