INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (101611, 20162, 0, "ねねね！\nみんなで記念撮影しよ？\nあとで見返したら絶対エモいっしょ！", 11, 0, 0, 1, 1, 10, 1201620005);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 20162, "", "", 91, "", "", "", "", "", 1201620006);
