INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("vo_travel_talk", 20182, "", "vo_travel_talk_20018_00", 21, "", "", 0, "", 0, 1201820003);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (118011, 20182, 0, "ぜぇ……ぜぇ……！\n本来、このような探索などは文官である\nわたくしの管轄外なのですけれど……！", 11, 0, 0, 1, 1, 10, 1201820004);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 20182, "", "", 91, "", "", "", "", "", 1201820005);
