INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("vo_travel_talk", 20182, "", "vo_travel_talk_20018_01", 21, "", "", 0, "", 0, 1201820007);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (118011, 20182, 0, "陛下直々のご命令とあれば、\nこのクレジッタ・キャッシュ！\nご満足いただける大秘宝を、\nなんとしても手に入れてみせますわ！", 11, 0, 0, 1, 1, 10, 1201820008);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 20182, "", "", 91, "", "", "", "", "", 1201820009);
