INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES ("vo_travel_talk", 20182, "", "vo_travel_talk_20018_02", 21, "", "", 0, "", 0, 1201820011);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (118011, 20182, 0, "……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！", 11, 0, 0, 1, 1, 10, 1201820012);
INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (0, 20182, "", "", 91, "", "", "", "", "", 1201820013);
