INSERT INTO `v1_0011c07719c837deb707bea935534f9fcd2fa2910e256da1f68049bfd32582c8` VALUES (105911, 20262, 0, "ふむ、ずいぶんと遠くまで来たようで\nございます。ですが、冒険というのは\nいつの時分にも楽しいものですね……♪", 11, 0, 0, 1, 1, 10, 1202620004);
